// msg.payload is already parsed JSON array by mqtt in
var numbers = msg.payload;
var text;
if (!Array.isArray(numbers) || numbers.length === 0) {
    text = 'No orders in queue';
} else {
    text = 'PREPARING:  ' + numbers.map(function(n){ return '#' + n; }).join('  ');
}
flow.set('queueText', text);
// Only send to display if we are not currently showing a ready alert
if (!flow.get('showingReady')) {
    msg.payload = {
        data: {
            message: text,
            textColor: '#FFFFFF',
            backgroundColor: '#1A1A2E',
            textSize: 'large',
            scrollDirection: 'fromRightToLeft',
            scrollSpeed: 4
        }
    };
    return msg;
}
return null;

var numbers = msg.payload;
if (!Array.isArray(numbers) || numbers.length === 0) {
    // Ready list cleared - cancel any pending revert and show queue
    var t = flow.get('revertTimer');
    if (t) { clearTimeout(t); flow.set('revertTimer', null); }
    flow.set('showingReady', false);
    var queueText = flow.get('queueText') || 'No orders in queue';
    msg.payload = {
        data: {
            message: queueText,
            textColor: '#FFFFFF',
            backgroundColor: '#1A1A2E',
            textSize: 'large',
            scrollDirection: 'fromRightToLeft',
            scrollSpeed: 4
        }
    };
    return msg;
}
var text = 'ORDER READY:  ' + numbers.map(function(n){ return '#' + n; }).join('  ');
flow.set('showingReady', true);
// Schedule revert back to queue view
var existing = flow.get('revertTimer');
if (existing) clearTimeout(existing);
var t = setTimeout(function() {
    // Node-RED function node does not have access to `node` inside setTimeout
    // so we use the trigger node output instead - see the trigger node
    flow.set('showingReady', false);
    flow.set('revertTimer', null);
}, 8000);
flow.set('revertTimer', t);
msg.payload = {
    data: {
        message: text,
        textColor: '#000000',
        backgroundColor: '#00CC44',
        textSize: 'large',
        scrollDirection: 'fromRightToLeft',
        scrollSpeed: 5,
        duration: { type: 'time', value: 8000 }
    }
};
return msg;
